import{_ as o,o as e,c as a,a2 as u}from"./chunks/framework.Crpw6aS5.js";const i=JSON.parse('{"title":"声誉经济","description":"","frontmatter":{},"headers":[],"relativePath":"05_quotes/by-theme/声誉.md","filePath":"05_quotes/by-theme/声誉.md"}'),r={name:"05_quotes/by-theme/声誉.md"};function l(q,t,c,p,s,_){return e(),a("div",null,[...t[0]||(t[0]=[u('<h1 id="声誉经济" tabindex="-1">声誉经济 <a class="header-anchor" href="#声誉经济" aria-label="Permalink to &quot;声誉经济&quot;">​</a></h1><blockquote><p>&quot;声誉是CEO最重要的无形资产，一旦失去，极难重建。&quot;——巴菲特</p></blockquote><p>巴菲特把声誉视为商业和个人决策的最高准则。</p><hr><h2 id="经典语录" tabindex="-1">经典语录 <a class="header-anchor" href="#经典语录" aria-label="Permalink to &quot;经典语录&quot;">​</a></h2><blockquote><p>&quot;我们愿意和那些行为正直、说话算数的管理层合作。如果一个人会为了自身利益撒谎，那我会假设他随时会这样做。&quot;</p></blockquote><blockquote><p>&quot;伯克希尔的声誉是我们最重要的资产。它让我们能够以更优惠的条件收购企业，吸引最优秀的人才。&quot;</p></blockquote><blockquote><p>&quot;声誉的建立需要二十年，毁掉它只需要五分钟。记住这一点，你会做出不同的决定。&quot;</p></blockquote><blockquote><p>&quot;我宁愿损失金钱也不愿损失声誉。金钱的损失可以弥补，声誉的损失永远无法完全恢复。&quot;</p></blockquote><blockquote><p>&quot;在我们所有的商业关系中，我们首先问的是：这是不是一个我们可以信任的交易？如果答案是否定的，不管条件多诱人，我们都会拒绝。&quot;</p></blockquote><hr><h2 id="出处年份" tabindex="-1">出处年份 <a class="header-anchor" href="#出处年份" aria-label="Permalink to &quot;出处年份&quot;">​</a></h2><p>1985年 · 1991年 · 1996年 · 2014年 · 2020年</p>',13)])])}const h=o(r,[["render",l]]);export{i as __pageData,h as default};
